(function(){var csrfToken='';var lastAuditLogs=[];var lastConfigChecks=[];var lastCmsRecords=[];var lastOpsAuditLogs=[];var lastSubmissionQueue=[];var lastCertificateQueue=[];function byId(id){return document.getElementById(id);}
function escapeHTML(str){var div=document.createElement('div');div.appendChild(document.createTextNode(String(str||'')));return div.innerHTML;}
function escapeHtml(str){return escapeHTML(str);}
function clearNode(node){if(!node)return;while(node.firstChild)node.removeChild(node.firstChild);}
function renderEmptyBody(body,colspan,message){if(!body)return;clearNode(body);var tr=document.createElement('tr');var td=document.createElement('td');td.colSpan=colspan;td.textContent=message;tr.appendChild(td);body.appendChild(tr);}
function appendTextCell(row,text){var cell=document.createElement('td');cell.textContent=text;row.appendChild(cell);return cell;}
function appendCodeCell(row,text){var cell=document.createElement('td');var code=document.createElement('code');code.textContent=text;cell.appendChild(code);row.appendChild(cell);return cell;}
function appendButtonGroup(cell,buttons){var group=document.createElement('div');group.className='button-group';(buttons||[]).forEach(function(config){var button=document.createElement('button');button.type='button';button.className=config.className;button.textContent=config.label;if(config.dataset){Object.keys(config.dataset).forEach(function(key){button.setAttribute('data-'+key,config.dataset[key]);});}
group.appendChild(button);});cell.appendChild(group);}
function setStatus(message){var status=byId('directory-moderation-status');if(status)status.textContent=message;}
function setCmsStatus(message){var status=byId('cms-status');if(status)status.textContent=message;}
function setOpsAuditStatus(message){var status=byId('ops-audit-status');if(status)status.textContent=message;}
function setSubmissionQueueStatus(message){var status=byId('submission-queue-status-text');if(status)status.textContent=message;}
function setCertificateQueueStatus(message){var status=byId('certificate-queue-status-text');if(status)status.textContent=message;}
function authHeaders(){var token=window.EFI&&window.EFI.Auth&&typeof window.EFI.Auth.getAccessToken==='function'?window.EFI.Auth.getAccessToken():'';return token?{Authorization:'Bearer '+token}:{};}
function secureHeaders(){var headers=Object.assign({},authHeaders());if(csrfToken)headers['X-EFI-CSRF']=csrfToken;return headers;}
function ensureCsrfToken(){if(csrfToken)return Promise.resolve(csrfToken);return fetch('/api/coach-directory?action=csrf',{headers:authHeaders()}).then(function(res){return res.json().catch(function(){return{};}).then(function(payload){if(!res.ok||payload.ok===false||!payload.csrf)throw new Error(payload.error||'Unable to issue CSRF token');csrfToken=payload.csrf;return csrfToken;});});}
function moderateListing(id,moderationStatus,verificationStatus,notes){return ensureCsrfToken().then(function(){return fetch('/api/coach-directory',{method:'POST',headers:Object.assign({'Content-Type':'application/json'},secureHeaders()),body:JSON.stringify({action:'moderate_listing',id:id,moderation_status:moderationStatus,verification_status:verificationStatus,moderation_notes:notes||''})});}).then(function(res){return res.json().catch(function(){return{};}).then(function(payload){if(!res.ok||payload.ok===false)throw new Error(payload.error||'Moderation failed');return payload;});});}
function archiveListing(id,notes){return ensureCsrfToken().then(function(){return fetch('/api/coach-directory',{method:'POST',headers:Object.assign({'Content-Type':'application/json'},secureHeaders()),body:JSON.stringify({action:'archive_listing',id:id,moderation_notes:notes||'Archived in CMS'})});}).then(function(res){return res.json().catch(function(){return{};}).then(function(payload){if(!res.ok||payload.ok===false)throw new Error(payload.error||'Archive failed');return payload;});});}
function updateListing(id,patch){return ensureCsrfToken().then(function(){return fetch('/api/coach-directory',{method:'POST',headers:Object.assign({'Content-Type':'application/json'},secureHeaders()),body:JSON.stringify(Object.assign({action:'update_listing',id:id},patch||{}))});}).then(function(res){return res.json().catch(function(){return{};}).then(function(payload){if(!res.ok||payload.ok===false)throw new Error(payload.error||'Listing update failed');return payload;});});}
function renderRows(records){var body=byId('directory-moderation-body');if(!body)return;if(!records.length){renderEmptyBody(body,7,'No pending listings.');setStatus('No pending listings in moderation queue.');return;}
setStatus(records.length+' pending listing'+(records.length===1?'':'s')+' loaded.');clearNode(body);records.forEach(function(row){var location=[row.city,row.state,row.zip].filter(Boolean).join(', ');var tr=document.createElement('tr');tr.setAttribute('data-directory-id',String(row.id||''));var nameCell=document.createElement('td');var strong=document.createElement('strong');strong.textContent=row.name||'Unknown';nameCell.appendChild(strong);nameCell.appendChild(document.createElement('br'));var meta=document.createElement('span');meta.style.fontSize='0.85rem';meta.style.color='var(--color-text-muted)';meta.textContent='ID: '+(row.credential_id||'Pending');nameCell.appendChild(meta);tr.appendChild(nameCell);appendTextCell(tr,location||'Unspecified');appendTextCell(tr,row.specialty||'Unspecified');appendTextCell(tr,row.verification_status||'pending');appendTextCell(tr,row.moderation_status||'pending');var noteCell=document.createElement('td');var input=document.createElement('input');input.className='form-control js-dir-note';input.type='text';input.placeholder='Add moderation note';input.value=row.moderation_notes||'';noteCell.appendChild(input);tr.appendChild(noteCell);var actionCell=document.createElement('td');appendButtonGroup(actionCell,[{className:'btn btn--sm btn--secondary js-dir-approve',label:'Approve'},{className:'btn btn--sm btn--ghost js-dir-reject',label:'Reject'},{className:'btn btn--sm btn--ghost js-dir-edit',label:'Edit'}]);tr.appendChild(actionCell);body.appendChild(tr);});}
function renderHistory(records){var body=byId('directory-history-body');if(!body)return;if(!records.length){renderEmptyBody(body,5,'No reviewed records yet.');return;}
clearNode(body);records.forEach(function(row){var tr=document.createElement('tr');var reviewedAt=row.last_reviewed||row.updated_at||'';appendTextCell(tr,row.name||'Unknown');appendTextCell(tr,(row.moderation_status||'pending')+' / '+(row.verification_status||'pending'));appendTextCell(tr,row.reviewer_email||'Unassigned');appendTextCell(tr,reviewedAt?new Date(reviewedAt).toLocaleString():'N/A');appendTextCell(tr,row.moderation_notes||'None');body.appendChild(tr);});}
function renderCmsRecords(records){var body=byId('cms-body');if(!body)return;if(!records.length){renderEmptyBody(body,8,'No records match current filters.');return;}
clearNode(body);records.forEach(function(row){var location=[row.city,row.state,row.zip].filter(Boolean).join(', ');var updated=row.updated_at?new Date(row.updated_at).toLocaleString():'N/A';var tr=document.createElement('tr');tr.setAttribute('data-cms-id',String(row.id||''));var nameCell=document.createElement('td');var strong=document.createElement('strong');strong.textContent=row.name||'Unknown';nameCell.appendChild(strong);nameCell.appendChild(document.createElement('br'));var small=document.createElement('small');small.textContent=row.credential_id||'No credential';nameCell.appendChild(small);tr.appendChild(nameCell);appendTextCell(tr,row.email||'');appendTextCell(tr,location);appendTextCell(tr,row.specialty||'');appendTextCell(tr,row.verification_status||'pending');appendTextCell(tr,row.moderation_status||'pending');appendTextCell(tr,updated);var actionCell=document.createElement('td');appendButtonGroup(actionCell,[{className:'btn btn--sm btn--ghost js-cms-edit',label:'Edit'},{className:'btn btn--sm btn--secondary js-cms-approve',label:'Approve'},{className:'btn btn--sm btn--ghost js-cms-archive',label:'Archive'}]);tr.appendChild(actionCell);body.appendChild(tr);});}
function bindModerationActions(){var body=byId('directory-moderation-body');if(!body)return;body.addEventListener('click',function(event){var target=event.target;if(!target||!target.closest('tr'))return;var row=target.closest('tr');var id=row.getAttribute('data-directory-id');if(!id)return;var noteInput=row.querySelector('.js-dir-note');var notes=noteInput?noteInput.value:'';if(target.classList.contains('js-dir-approve')){target.disabled=true;moderateListing(id,'approved','verified',notes||'Approved in admin queue').then(function(){return Promise.all([loadQueue(),loadCmsRecords()]);}).catch(function(err){setStatus(err.message||'Unable to approve listing.');}).finally(function(){target.disabled=false;});}
if(target.classList.contains('js-dir-reject')){target.disabled=true;moderateListing(id,'rejected','pending',notes||'Rejected in admin queue').then(function(){return Promise.all([loadQueue(),loadCmsRecords()]);}).catch(function(err){setStatus(err.message||'Unable to reject listing.');}).finally(function(){target.disabled=false;});}
if(target.classList.contains('js-dir-edit')){target.disabled=true;var currentName=row.children[0]?row.children[0].innerText.split('\n')[0]:'';var currentCityStateZip=row.children[1]?row.children[1].innerText:'';var currentSpecialty=row.children[2]?row.children[2].innerText:'';var name=window.prompt('Update name',currentName)||currentName;var location=window.prompt('Update location as City, ST, ZIP',currentCityStateZip)||currentCityStateZip;var specialty=window.prompt('Update specialty',currentSpecialty)||currentSpecialty;var parts=location.split(',').map(function(x){return x.trim();});updateListing(id,{name:name,city:parts[0]||'',state:parts[1]||'',zip:parts[2]||'',specialty:specialty}).then(function(){return Promise.all([loadQueue(),loadCmsRecords()]);}).catch(function(err){setStatus(err.message||'Unable to update listing.');}).finally(function(){target.disabled=false;});}});}
function bindCmsActions(){var body=byId('cms-body');if(!body)return;body.addEventListener('click',function(event){var target=event.target;if(!target||!target.closest('tr'))return;var row=target.closest('tr');var id=row.getAttribute('data-cms-id');if(!id)return;var record=(lastCmsRecords||[]).find(function(r){return String(r.id)===String(id);})||{};if(target.classList.contains('js-cms-edit')){target.disabled=true;var name=window.prompt('Update name',record.name||'')||record.name||'';var location=window.prompt('Update location as City, ST, ZIP',[record.city,record.state,record.zip].filter(Boolean).join(', '))||'';var specialty=window.prompt('Update specialty',record.specialty||'')||record.specialty||'';var website=window.prompt('Update website',record.website||'')||record.website||'';var parts=location.split(',').map(function(x){return x.trim();});updateListing(id,{name:name,city:parts[0]||'',state:parts[1]||'',zip:parts[2]||'',specialty:specialty,website:website}).then(function(){return Promise.all([loadQueue(),loadCmsRecords()]);}).catch(function(err){setCmsStatus(err.message||'Unable to update record.');}).finally(function(){target.disabled=false;});}
if(target.classList.contains('js-cms-approve')){target.disabled=true;moderateListing(id,'approved','verified','Approved in CMS table').then(function(){return Promise.all([loadQueue(),loadCmsRecords()]);}).catch(function(err){setCmsStatus(err.message||'Unable to approve record.');}).finally(function(){target.disabled=false;});}
if(target.classList.contains('js-cms-archive')){target.disabled=true;var notes=window.prompt('Archive note','Archived in CMS')||'Archived in CMS';archiveListing(id,notes).then(function(){return Promise.all([loadQueue(),loadCmsRecords()]);}).catch(function(err){setCmsStatus(err.message||'Unable to archive record.');}).finally(function(){target.disabled=false;});}});}
function readCmsFilters(){return{q:(byId('cms-search')&&byId('cms-search').value||'').trim(),moderation_status:(byId('cms-moderation')&&byId('cms-moderation').value||'').trim(),verification_status:(byId('cms-verification')&&byId('cms-verification').value||'').trim()};}
function loadQueue(){setStatus('Loading pending records...');return fetch('/api/coach-directory?include_pending=1&audit=1&audit_limit=200&limit=500',{headers:authHeaders()}).then(function(res){return res.json().catch(function(){return{};}).then(function(payload){if(!res.ok||payload.ok===false)throw new Error(payload.error||'Unable to load moderation queue');return payload;});}).then(function(payload){var all=payload.records||[];var pending=all.filter(function(row){return String(row.moderation_status||'').toLowerCase()==='pending';});lastAuditLogs=payload.audit_logs||[];var reviewed=lastAuditLogs.slice(0,20).map(function(log){return{name:(log.metadata&&(log.metadata.name||log.metadata.city||'Directory Record'))||'Directory Record',moderation_status:(log.metadata&&log.metadata.moderation_status)||log.action||'updated',verification_status:(log.metadata&&log.metadata.verification_status)||'n/a',reviewer_email:log.actor_email||'Unassigned',last_reviewed:log.created_at,updated_at:log.created_at,moderation_notes:(log.metadata&&(log.metadata.moderation_notes||log.metadata.notes))||''};});if(!reviewed.length){reviewed=all.filter(function(row){return String(row.moderation_status||'').toLowerCase()!=='pending';}).sort(function(a,b){return String(b.last_reviewed||b.updated_at||'').localeCompare(String(a.last_reviewed||a.updated_at||''));}).slice(0,20);}
renderRows(pending);renderHistory(reviewed);}).catch(function(err){var body=byId('directory-moderation-body');renderEmptyBody(body,7,'Queue unavailable.');var history=byId('directory-history-body');renderEmptyBody(history,5,'History unavailable.');setStatus(err.message||'Unable to load queue.');});}
function loadCmsRecords(){var filters=readCmsFilters();var params=new URLSearchParams({include_pending:'1',limit:'500'});if(filters.q)params.set('q',filters.q);if(filters.moderation_status)params.set('moderation_status',filters.moderation_status);if(filters.verification_status)params.set('verification_status',filters.verification_status);setCmsStatus('Loading CMS records...');return fetch('/api/coach-directory?'+params.toString(),{headers:authHeaders()}).then(function(res){return res.json().catch(function(){return{};}).then(function(payload){if(!res.ok||payload.ok===false)throw new Error(payload.error||'Unable to load CMS records');return payload;});}).then(function(payload){lastCmsRecords=payload.records||[];renderCmsRecords(lastCmsRecords);setCmsStatus('CMS loaded: '+(payload.total_filtered||lastCmsRecords.length)+' record(s) match filters.');}).catch(function(err){lastCmsRecords=[];renderCmsRecords([]);setCmsStatus(err.message||'Unable to load CMS records.');});}
function renderOpsConfig(payload){var status=byId('ops-config-status');var body=byId('ops-config-body');if(!status||!body)return;var checks=(payload&&payload.checks)||[];lastConfigChecks=checks.slice();if(!checks.length){status.textContent='No config data returned.';renderEmptyBody(body,3,'No config data.');return;}
clearNode(body);checks.forEach(function(item){var tr=document.createElement('tr');appendCodeCell(tr,item.name||'');appendTextCell(tr,item.exists?'Yes':'No');appendTextCell(tr,item.exists?(item.strong?'Pass':'Weak'):'N/A');body.appendChild(tr);});if(payload.summary&&payload.summary.launch_ready){status.textContent='All required launch variables are configured.';return;}
var missing=(payload&&payload.missing)||[];var weak=(payload&&payload.weak)||[];status.textContent='Missing: '+(missing.length?missing.join(', '):'none')+'. Weak: '+(weak.length?weak.join(', '):'none')+'.';}
function loadOpsConfig(){var status=byId('ops-config-status');var body=byId('ops-config-body');if(!status||!body)return Promise.resolve();status.textContent='Loading config checks...';return fetch('/api/ops-config',{headers:authHeaders()}).then(function(res){return res.json().catch(function(){return{};}).then(function(payload){if(!res.ok||payload.ok===false)throw new Error(payload.error||'Unable to load config checks');return payload;});}).then(renderOpsConfig).catch(function(err){status.textContent=err.message||'Unable to load config checks.';renderEmptyBody(body,3,'Config checks unavailable.');});}
function renderOpsAudit(logs){var body=byId('ops-audit-body');if(!body)return;if(!logs.length){renderEmptyBody(body,5,'No ops audit events loaded.');return;}
clearNode(body);logs.forEach(function(log){var metadata=log.metadata||{};var note=metadata.reason||metadata.error||metadata.email||metadata.verification_mode||JSON.stringify(metadata||{});var tr=document.createElement('tr');appendTextCell(tr,log.created_at?new Date(log.created_at).toLocaleString():'N/A');appendCodeCell(tr,log.action||'');appendTextCell(tr,(log.actor_role||'unknown')+(log.actor_email?' / '+log.actor_email:''));appendTextCell(tr,(log.target_type||'n/a')+(log.target_id?' / '+log.target_id:''));appendTextCell(tr,note);body.appendChild(tr);});}
function formatSubmissionStateLabel(state){var normalized=String(state||'').trim();if(!normalized)return'Pending';return normalized.replace(/_/g,' ').replace(/\b\w/g,function(match){return match.toUpperCase();});}
function renderSubmissionQueue(records){var body=byId('submission-queue-body');if(!body)return;if(!records.length){renderEmptyBody(body,7,'No submissions match current filters.');return;}
clearNode(body);records.forEach(function(row){var label=row.kind==='capstone'?'Capstone':('Module '+String(row.module_id||'?'));var releaseText=row.release_at?new Date(row.release_at).toLocaleString():'Immediate release';var scoreText=typeof row.internal_score==='number'?(row.internal_score+'%'):(typeof row.score==='number'?(row.score+'%'):'Pending');var workflowState=formatSubmissionStateLabel(row.workflow_state||row.status);var entitlementText=row.entitlement_active?'Unlocked':('Missing '+String(row.required_item_id||'required purchase'));var internalFeedback=row.internal_feedback||{};var reviewerOverride=internalFeedback.reviewer_override||{};var reviewHistory=Array.isArray(internalFeedback.review_history)?internalFeedback.review_history:[];var attachments=internalFeedback.submission_meta&&Array.isArray(internalFeedback.submission_meta.attachments)?internalFeedback.submission_meta.attachments:[];var noteParts=[];if(internalFeedback.summary)noteParts.push(internalFeedback.summary);if(reviewerOverride.reviewer_notes)noteParts.push('Reviewer: '+reviewerOverride.reviewer_notes);if(reviewHistory.length)noteParts.push('Reviews logged: '+reviewHistory.length);if(attachments.length)noteParts.push('Evidence links: '+attachments.map(function(item){return item.label||item.url;}).join(', '));noteParts.push('Release: '+releaseText);if(row.notified_at)noteParts.push('Notified '+new Date(row.notified_at).toLocaleString());var tr=document.createElement('tr');tr.setAttribute('data-submission-id',String(row.id||''));var learnerCell=document.createElement('td');var strong=document.createElement('strong');strong.textContent=row.email||'Unknown';learnerCell.appendChild(strong);learnerCell.appendChild(document.createElement('br'));var small=document.createElement('small');small.textContent=row.id||'';learnerCell.appendChild(small);tr.appendChild(learnerCell);appendTextCell(tr,label);appendTextCell(tr,workflowState);appendTextCell(tr,scoreText);appendTextCell(tr,entitlementText);appendTextCell(tr,noteParts.join(' | '));var actionCell=document.createElement('td');var scoreInput=document.createElement('input');scoreInput.className='form-control js-submission-score';scoreInput.type='number';scoreInput.min='0';scoreInput.max='100';scoreInput.step='1';scoreInput.placeholder='Score';scoreInput.value=typeof row.internal_score==='number'?String(row.internal_score):(typeof row.score==='number'?String(row.score):'');scoreInput.style.marginBottom='var(--space-xs)';actionCell.appendChild(scoreInput);var noteInput=document.createElement('textarea');noteInput.className='form-control js-submission-note';noteInput.rows=3;noteInput.placeholder='Reviewer notes for the learner and audit trail';noteInput.style.minWidth='18rem';noteInput.style.marginBottom='var(--space-xs)';noteInput.value=reviewerOverride.reviewer_notes||'';actionCell.appendChild(noteInput);var historyText=document.createElement('div');historyText.style.fontSize='0.8rem';historyText.style.color='var(--color-text-muted)';historyText.style.marginBottom='var(--space-xs)';if(reviewHistory.length){var latestReview=reviewHistory[reviewHistory.length-1]||{};historyText.textContent='Latest review: '+formatSubmissionStateLabel(latestReview.decision||latestReview.status||'')+' on '+(latestReview.reviewed_at?new Date(latestReview.reviewed_at).toLocaleString():'N/A');}else{historyText.textContent='No reviewer actions logged yet.';}
actionCell.appendChild(historyText);appendButtonGroup(actionCell,[{className:'btn btn--sm btn--secondary js-submission-release',label:'Release'},{className:'btn btn--sm btn--ghost js-submission-pass',label:'Pass'},{className:'btn btn--sm btn--ghost js-submission-revise',label:'Revise'}]);tr.appendChild(actionCell);body.appendChild(tr);});}
function renderCertificateQueue(records){var body=byId('certificate-queue-body');if(!body)return;if(!records.length){renderEmptyBody(body,7,'No certificate purchases match current filters.');return;}
clearNode(body);records.forEach(function(row){var items=(row.items||[]).map(function(item){return item.name||item.id||'item';}).join(', ');var decision=row.reviewerDecision?(row.reviewerDecision+(row.reviewedAt?' ('+new Date(row.reviewedAt).toLocaleDateString()+')':'')):'Pending';var tr=document.createElement('tr');tr.setAttribute('data-purchase-id',String(row.id||''));tr.setAttribute('data-credential-id',String(row.credentialId||''));tr.setAttribute('data-email',String(row.email||''));var learnerCell=document.createElement('td');var strong=document.createElement('strong');strong.textContent=row.email||'Unknown';learnerCell.appendChild(strong);learnerCell.appendChild(document.createElement('br'));var small=document.createElement('small');small.textContent=row.id||'';learnerCell.appendChild(small);tr.appendChild(learnerCell);appendTextCell(tr,row.credentialId||'Pending');appendTextCell(tr,row.date?new Date(row.date).toLocaleString():'N/A');appendTextCell(tr,'$'+String(row.total||0));appendTextCell(tr,decision);appendTextCell(tr,items||'Certificate');var actionCell=document.createElement('td');appendButtonGroup(actionCell,[{className:'btn btn--sm btn--secondary js-certificate-approve',label:'Approve'},{className:'btn btn--sm btn--ghost js-certificate-hold',label:'Hold'},{className:'btn btn--sm btn--ghost js-certificate-reject',label:'Reject'}]);tr.appendChild(actionCell);body.appendChild(tr);});}
function loadOpsAudit(){setOpsAuditStatus('Loading audit trail...');return fetch('/api/audit-logs?limit=100',{headers:authHeaders()}).then(function(res){return res.json().catch(function(){return{};}).then(function(payload){if(!res.ok||payload.ok===false)throw new Error(payload.error||'Unable to load ops audit trail');return payload;});}).then(function(payload){lastOpsAuditLogs=payload.logs||[];renderOpsAudit(lastOpsAuditLogs);setOpsAuditStatus('Loaded '+lastOpsAuditLogs.length+' audit event(s).');}).catch(function(err){lastOpsAuditLogs=[];renderOpsAudit([]);setOpsAuditStatus(err.message||'Unable to load ops audit trail.');});}
function readSubmissionQueueFilters(){return{kind:(byId('submission-queue-kind')&&byId('submission-queue-kind').value||'').trim(),status:(byId('submission-queue-status')&&byId('submission-queue-status').value||'').trim(),email:(byId('submission-queue-email')&&byId('submission-queue-email').value||'').trim()};}
function loadSubmissionQueue(){var filters=readSubmissionQueueFilters();var params=new URLSearchParams({review_queue:'1',limit:'100'});if(filters.kind)params.set('kind',filters.kind);if(filters.status)params.set('status',filters.status);if(filters.email)params.set('email',filters.email);setSubmissionQueueStatus('Loading submissions...');return fetch('/api/submissions?'+params.toString(),{headers:authHeaders()}).then(function(res){return res.json().catch(function(){return{};}).then(function(payload){if(!res.ok||payload.ok===false)throw new Error(payload.error||'Unable to load submission queue');return payload;});}).then(function(payload){lastSubmissionQueue=payload.submissions||[];renderSubmissionQueue(lastSubmissionQueue);setSubmissionQueueStatus('Loaded '+lastSubmissionQueue.length+' submission(s).');}).catch(function(err){lastSubmissionQueue=[];renderSubmissionQueue([]);setSubmissionQueueStatus(err.message||'Unable to load submission queue.');});}
function readCertificateQueueFilters(){return{email:(byId('certificate-queue-email')&&byId('certificate-queue-email').value||'').trim(),include_framed:(byId('certificate-queue-framed')&&byId('certificate-queue-framed').value||'0').trim()};}
function loadCertificateQueue(){var filters=readCertificateQueueFilters();var params=new URLSearchParams({review_queue:'1',limit:'100',include_framed:filters.include_framed||'0'});if(filters.email)params.set('email',filters.email);setCertificateQueueStatus('Loading certificate purchases...');return fetch('/api/verify?'+params.toString(),{headers:authHeaders()}).then(function(res){return res.json().catch(function(){return{};}).then(function(payload){if(!res.ok||payload.ok===false)throw new Error(payload.error||'Unable to load certificate queue');return payload;});}).then(function(payload){lastCertificateQueue=payload.purchases||[];renderCertificateQueue(lastCertificateQueue);setCertificateQueueStatus('Loaded '+lastCertificateQueue.length+' certificate purchase record(s).');}).catch(function(err){lastCertificateQueue=[];renderCertificateQueue([]);setCertificateQueueStatus(err.message||'Unable to load certificate queue.');});}
function postJson(url,payload){return fetch(url,{method:'POST',headers:Object.assign({'Content-Type':'application/json'},secureHeaders()),body:JSON.stringify(payload)}).then(function(res){return res.json().catch(function(){return{};}).then(function(data){if(!res.ok||data.ok===false)throw new Error(data.error||'Request failed');return data;});});}
function bindExportActions(){var auditBtn=byId('directory-audit-export-btn');if(auditBtn){auditBtn.addEventListener('click',function(){if(!lastAuditLogs.length){setStatus('No audit records loaded to export yet.');return;}
var rows=lastAuditLogs.map(function(log){return[log.id||'',log.created_at||'',log.actor_role||'',log.actor_email||'',log.action||'',log.target_id||'',JSON.stringify(log.metadata||{})];});downloadCsv('efi-directory-audit-'+new Date().toISOString().slice(0,10)+'.csv',['id','created_at','actor_role','actor_email','action','target_id','metadata'],rows);});}
var configBtn=byId('ops-config-export-btn');if(configBtn){configBtn.addEventListener('click',function(){if(!lastConfigChecks.length){var status=byId('ops-config-status');if(status)status.textContent='No config checks loaded to export yet.';return;}
var rows=lastConfigChecks.map(function(item){return[item.name,item.exists?'yes':'no',item.strong?'pass':'weak'];});downloadCsv('efi-launch-config-'+new Date().toISOString().slice(0,10)+'.csv',['variable','configured','strength'],rows);});}
var cmsExportBtn=byId('cms-export-btn');if(cmsExportBtn){cmsExportBtn.addEventListener('click',function(){if(!lastCmsRecords.length){setCmsStatus('No CMS records loaded to export.');return;}
var rows=lastCmsRecords.map(function(r){return[r.id||'',r.name||'',r.email||'',r.city||'',r.state||'',r.zip||'',r.specialty||'',Array.isArray(r.delivery_modes)?r.delivery_modes.join('|'):'',r.credential_id||'',r.verification_status||'',r.moderation_status||'',r.updated_at||''];});downloadCsv('efi-directory-records-'+new Date().toISOString().slice(0,10)+'.csv',['id','name','email','city','state','zip','specialty','delivery_modes','credential_id','verification_status','moderation_status','updated_at'],rows);});}
var opsAuditExportBtn=byId('ops-audit-export-btn');if(opsAuditExportBtn){opsAuditExportBtn.addEventListener('click',function(){if(!lastOpsAuditLogs.length){setOpsAuditStatus('No ops audit events loaded to export.');return;}
var rows=lastOpsAuditLogs.map(function(log){return[log.id||'',log.created_at||'',log.actor_role||'',log.actor_email||'',log.action||'',log.target_type||'',log.target_id||'',log.ip||'',JSON.stringify(log.metadata||{})];});downloadCsv('efi-ops-audit-'+new Date().toISOString().slice(0,10)+'.csv',['id','created_at','actor_role','actor_email','action','target_type','target_id','ip','metadata'],rows);});}}
function bindCmsFilterControls(){var refreshBtn=byId('cms-refresh-btn');if(refreshBtn)refreshBtn.addEventListener('click',loadCmsRecords);['cms-search','cms-moderation','cms-verification'].forEach(function(id){var el=byId(id);if(!el)return;el.addEventListener(id==='cms-search'?'input':'change',loadCmsRecords);});}
function bindOpsAuditControls(){var refreshBtn=byId('ops-audit-refresh-btn');if(refreshBtn)refreshBtn.addEventListener('click',loadOpsAudit);}
function bindReviewControls(){var submissionBtn=byId('review-submission-btn');if(submissionBtn){submissionBtn.addEventListener('click',function(){var status=byId('review-submission-status');ensureCsrfToken().then(function(){var payload={action:'review_submission',submission_id:(byId('review-submission-id').value||'').trim(),decision:(byId('review-submission-decision').value||'').trim(),reviewer_notes:(byId('review-submission-notes').value||'').trim()};var score=(byId('review-submission-score').value||'').trim();if(score)payload.score=Number(score);if(payload.decision==='release_now')payload.release_now=true;status.textContent='Recording submission decision...';return postJson('/api/submissions',payload);}).then(function(result){status.textContent=result.message||'Submission decision recorded.';loadOpsAudit();}).catch(function(err){status.textContent=err.message||'Unable to record submission decision.';});});}
var certificateBtn=byId('review-certificate-btn');if(certificateBtn){certificateBtn.addEventListener('click',function(){var status=byId('review-certificate-status');ensureCsrfToken().then(function(){status.textContent='Recording certificate decision...';return postJson('/api/verify',{action:'review_certificate',email:(byId('review-certificate-email').value||'').trim(),credential_id:(byId('review-certificate-id').value||'').trim(),decision:(byId('review-certificate-decision').value||'').trim(),reviewer_notes:(byId('review-certificate-notes').value||'').trim()});}).then(function(result){status.textContent=result.message||'Certificate decision recorded.';loadOpsAudit();}).catch(function(err){status.textContent=err.message||'Unable to record certificate decision.';});});}}
function bindSubmissionQueueControls(){var refreshBtn=byId('submission-queue-refresh-btn');if(refreshBtn)refreshBtn.addEventListener('click',loadSubmissionQueue);['submission-queue-kind','submission-queue-status','submission-queue-email'].forEach(function(id){var el=byId(id);if(!el)return;el.addEventListener(id==='submission-queue-email'?'input':'change',loadSubmissionQueue);});var body=byId('submission-queue-body');if(!body)return;body.addEventListener('click',function(event){var target=event.target;if(!target||!target.closest('tr'))return;var row=target.closest('tr');var submissionId=row.getAttribute('data-submission-id');var submission=(lastSubmissionQueue||[]).find(function(item){return String(item.id)===String(submissionId);})||null;if(!submissionId||!submission)return;function runDecision(decision,defaultNotes,fallbackScore){var notesField=row.querySelector('.js-submission-note');var scoreField=row.querySelector('.js-submission-score');var reviewerNotes=notesField&&String(notesField.value||'').trim()?String(notesField.value||'').trim():defaultNotes;var scoreValue=scoreField&&String(scoreField.value||'').trim()!==''?Number(scoreField.value):fallbackScore;if(reviewerNotes.length<8){setSubmissionQueueStatus('Reviewer notes must be at least 8 characters.');if(notesField)notesField.focus();return Promise.resolve();}
ensureCsrfToken().then(function(){setSubmissionQueueStatus('Recording reviewer decision...');var payload={action:'review_submission',submission_id:submissionId,decision:decision,reviewer_notes:reviewerNotes};if(scoreValue!=null&&Number.isFinite(scoreValue))payload.score=scoreValue;if(decision==='release_now')payload.release_now=true;return postJson('/api/submissions',payload);}).then(function(){return Promise.all([loadSubmissionQueue(),loadOpsAudit()]);}).catch(function(err){setSubmissionQueueStatus(err.message||'Unable to record reviewer decision.');});}
if(target.classList.contains('js-submission-release')){runDecision('release_now','Manual release after reviewer check.');}
if(target.classList.contains('js-submission-pass')){var passScore=typeof submission.internal_score==='number'?Math.max(75,submission.internal_score):(typeof submission.score==='number'?Math.max(75,submission.score):85);runDecision('override_pass','Manual pass after reviewer review.',passScore);}
if(target.classList.contains('js-submission-revise')){var failScore=typeof submission.internal_score==='number'?Math.min(74,submission.internal_score):(typeof submission.score==='number'?Math.min(74,submission.score):60);runDecision('needs_revision','Needs revision after reviewer review.',failScore);}});}
function bindCertificateQueueControls(){var refreshBtn=byId('certificate-queue-refresh-btn');if(refreshBtn)refreshBtn.addEventListener('click',loadCertificateQueue);['certificate-queue-email','certificate-queue-framed'].forEach(function(id){var el=byId(id);if(!el)return;el.addEventListener(id==='certificate-queue-email'?'input':'change',loadCertificateQueue);});var body=byId('certificate-queue-body');if(!body)return;body.addEventListener('click',function(event){var target=event.target;if(!target||!target.closest('tr'))return;var row=target.closest('tr');var email=row.getAttribute('data-email');var credentialId=row.getAttribute('data-credential-id');if(!email)return;function runDecision(decision,defaultNotes){ensureCsrfToken().then(function(){setCertificateQueueStatus('Recording certificate decision...');return postJson('/api/verify',{action:'review_certificate',email:email,credential_id:credentialId,decision:decision,reviewer_notes:window.prompt('Reviewer notes',defaultNotes)||defaultNotes});}).then(function(){return Promise.all([loadCertificateQueue(),loadOpsAudit()]);}).catch(function(err){setCertificateQueueStatus(err.message||'Unable to record certificate decision.');});}
if(target.classList.contains('js-certificate-approve')){runDecision('approve_release','Approve release after certificate review.');}
if(target.classList.contains('js-certificate-hold')){runDecision('hold','Hold certificate pending additional review.');}
if(target.classList.contains('js-certificate-reject')){runDecision('reject','Reject certificate release after review.');}});}
document.addEventListener('DOMContentLoaded',function(){if(!byId('directory-moderation-body'))return;bindModerationActions();bindCmsActions();bindCmsFilterControls();bindSubmissionQueueControls();bindCertificateQueueControls();bindOpsAuditControls();bindReviewControls();bindExportActions();loadQueue();loadCmsRecords();loadSubmissionQueue();loadCertificateQueue();loadOpsConfig();loadOpsAudit();});})();